// // This module inverts the behavior of the clock gating logic, holding ENCLK high when EN is low and passing CLK to ENCLK when EN is high.
module clock_gate (
  input CLK,
  input EN,
  input TE,
  output reg ENCLK
);

  always @(*) begin
    if (TE) begin
      ENCLK <= 0;
    end else if (EN) begin
      ENCLK <= CLK;
    end else begin
      ENCLK <= 0;
    end
  end

endmodule
